# Now let's find patterns in the background area and analyze them
# For example 0
for i, s in enumerate(train_samples):
    inp = np.array(s['input'])
    out = np.array(s['output'])
    H, W = inp.shape
    bg = int(inp[0, 0])

    print(f"=== Example {i} (bg={bg}) ===")

    # Find background rows (rows that are all background or contain patterns)
    # vs band rows
    band_rows = set()
    for r in range(H):
        row = inp[r]
        unique = set(int(x) for x in row)
        if bg not in unique and len(unique) <= 2:
            band_rows.add(r)
        elif all(x == bg for x in row):
            pass  # separator

    # Find non-background, non-band cells in background area
    bg_area_end = min(band_rows) if band_rows else H
    print(f"Background area: rows 0-{bg_area_end-1}")

    # Find small pattern cells
    pattern_cells = []
    for r in range(bg_area_end):
        for c in range(W):
            if int(inp[r, c]) != bg:
                pattern_cells.append((r, c, int(inp[r, c])))

    if pattern_cells:
        print("Pattern cells in background:")
        for r, c, v in pattern_cells:
            print(f"  ({r},{c}): {v}")

    # Show output differences in bands
    print("\nOutput changes in bands:")
    for r in sorted(band_rows):
        for c in range(W):
            if int(inp[r, c]) != int(out[r, c]):
                print(f"  ({r},{c}): {int(inp[r,c])} -> {int(out[r,c])}")
    print()

