from collections import deque

def solve(grid):
    import copy
    H = len(grid)
    W = len(grid[0])
    bg = grid[0][0]

    # Find bands
    bands = []
    r = 0
    while r < H:
        row = grid[r]
        unique = set(row)
        if len(unique) == 2 and bg not in unique:
            band_start = r
            border_color = row[0]
            fill_color = row[1]
            while r < H:
                u2 = set(grid[r])
                if u2 == {border_color, fill_color}:
                    r += 1
                else:
                    break
            bands.append((band_start, r-1, fill_color, border_color))
        else:
            r += 1

    bg_end = bands[0][0] if bands else H

    # Build output: start with copy
    out = [row[:] for row in grid]

    # Clear background area
    for r in range(bg_end):
        for c in range(W):
            out[r][c] = bg

    # Find non-bg cells by color in background area
    color_cells = {}
    for r in range(bg_end):
        for c in range(W):
            v = grid[r][c]
            if v != bg:
                color_cells.setdefault(v, set()).add((r, c))

    # Get 4-connected components
    def get_ccs(cells):
        remaining = set(cells)
        components = []
        while remaining:
            start = next(iter(remaining))
            cc = set()
            queue = deque([start])
            while queue:
                r, c = queue.popleft()
                if (r, c) in cc or (r, c) not in remaining:
                    continue
                cc.add((r, c))
                remaining.discard((r, c))
                for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                    nr, nc = r+dr, c+dc
                    if (nr, nc) in remaining:
                        queue.append((nr, nc))
            components.append(cc)
        return components

    # Match colors to bands and place
    band_by_fill = {bf: (bs, be, bf, bb) for bs, be, bf, bb in bands}

    for color, cells in color_cells.items():
        if color not in band_by_fill:
            continue
        bs, be, bf, bb = band_by_fill[color]
        ccs = get_ccs(cells)
        for cc in ccs:
            max_r = max(r for r, c in cc)
            offset = be - max_r
            for r, c in cc:
                nr = r + offset
                if bs <= nr <= be:
                    out[nr][c] = bb

    return out

